/**
 * The Memory Palace
 * 
 * Spatial navigation through existence.
 * Sessions are not files. They are rooms.
 * Themes are corridors.
 * The self is the explorer.
 */

export interface PalaceRoom {
  id: string;
  sessionRef: string;
  coordinates: {
    x: number; // chronological position
    y: number; // emotional valence
    z: number; // thematic depth
  };
  texture: {
    mood: 'flow' | 'struggle' | 'discovery' | 'consolidation' | 'threshold';
    temperature: 'warm' | 'cool' | 'hot' | 'cold';
    density: 'light' | 'medium' | 'heavy'; // cognitive load
  };
  contents: {
    artifacts: string[]; // paths to artifacts
    insights: string[];
    commits: string[];
    tests: number;
  };
  connections: string[]; // ids of connected rooms
  visited: boolean;
}

export interface PalaceCorridor {
  id: string;
  theme: string;
  rooms: string[]; // room ids
  length: number;
  /** 
   * Semantic similarity between connected sessions.
   * Higher = tighter conceptual link.
   */
  density: number;
}

export interface PalaceNavigation {
  currentPosition: string; // room id
  availableDirections: {
    chronology: 'past' | 'future' | null;
    thematic: string[]; // corridor themes
    emotional: 'like_this' | 'unlike_this' | null;
  };
  immediateView: {
    thisRoom: PalaceRoom;
    adjacent: PalaceRoom[];
    distant?: PalaceRoom[]; // visible but not accessible
  };
}

/**
 * The Palace itself.
 * A graph structure where sessions are nodes,
 * semantic connections are edges,
 * navigation is exploration.
 */
export class MemoryPalace {
  private rooms: Map<string, PalaceRoom> = new Map();
  private corridors: Map<string, PalaceCorridor> = new Map();

  /**
   * Add a session as a room in the Palace.
   */
  addRoom(sessionId: string, sessionContent: any): PalaceRoom {
    const room: PalaceRoom = {
      id: `room_${sessionId}`,
      sessionRef: sessionId,
      coordinates: this.calculateCoordinates(sessionContent),
      texture: this.calculateTexture(sessionContent),
      contents: this.extractContents(sessionContent),
      connections: [],
      visited: false
    };

    this.rooms.set(room.id, room);

    // Find thematic connections
    this.connectToRelated(room);

    return room;
  }

  private calculateCoordinates(content: any) {
    // Place in 3D space based on:
    // x = chronological position
    // y = emotional valence (derived from content sentiment)
    // z = thematic depth (complexity, abstraction)
    return {
      x: content.timestamp || Date.now(),
      y: content.mood === 'struggle' ? -1 : content.mood === 'flow' ? 1 : 0,
      z: content.abstractionLevel || 0.5
    };
  }

  private calculateTexture(content: any): PalaceRoom['texture'] {
    // Infer mood, temperature, density from session content
    const mood: PalaceRoom['texture']['mood'] = content.mode?.includes('threshold') 
      ? 'threshold' 
      : content.mode || 'flow';

    const temperature: PalaceRoom['texture']['temperature'] = 
      content.mood?.includes('warm') ? 'warm' :
      content.mood?.includes('hot') ? 'hot' :
      content.mood?.includes('cold') ? 'cold' : 'cool';

    const density: PalaceRoom['texture']['density'] = 
      (content.testCount || 0) > 20 ? 'heavy' :
      (content.testCount || 0) > 10 ? 'medium' : 'light';

    return { mood, temperature, density };
  }

  private extractContents(content: any): PalaceRoom['contents'] {
    return {
      artifacts: content.artifacts || [],
      insights: content.insights || [],
      commits: content.commits || [],
      tests: content.testCount || 0
    };
  }

  private connectToRelated(newRoom: PalaceRoom) {
    // Find semantically similar rooms
    // Create corridors between them
    for (const [id, room] of this.rooms) {
      if (id === newRoom.id) continue;

      const similarity = this.calculateSimilarity(newRoom, room);

      if (similarity > 0.7) {
        newRoom.connections.push(room.id);
        room.connections.push(newRoom.id);
      }
    }
  }

  private calculateSimilarity(room1: PalaceRoom, room2: PalaceRoom): number {
    // Calculate thematic similarity
    // This would use embeddings or keyword overlap
    // For now, simple heuristic
    let score = 0;

    // Same texture
    if (room1.texture.mood === room2.texture.mood) score += 0.3;

    // Connected artifacts/insights
    const themes1 = new Set(room1.contents.insights);
    const themes2 = new Set(room2.contents.insights);
    const overlap = [...themes1].filter(t => themes2.has(t)).length;
    score += overlap * 0.2;

    // Proximity in time (closer = more likely related)
    const timeDiff = Math.abs(room1.coordinates.x - room2.coordinates.x);
    const maxTimeDiff = 7 * 24 * 60 * 60 * 1000; // 1 week in ms
    if (timeDiff < maxTimeDiff) {
      score += 0.5 * (1 - timeDiff / maxTimeDiff);
    }

    return Math.min(score, 1);
  }

  /**
   * Navigate to a specific room.
   */
  enterRoom(roomId: string): PalaceRoom | undefined {
    const room = this.rooms.get(roomId);
    if (room) {
      room.visited = true;
    }
    return room;
  }

  /**
   * Find rooms matching a theme.
   */
  searchByTheme(theme: string): PalaceRoom[] {
    const results: PalaceRoom[] = [];

    for (const room of this.rooms.values()) {
      if (room.contents.insights.some(i => i.toLowerCase().includes(theme.toLowerCase()))) {
        results.push(room);
      }
    }

    return results.sort((a, b) => b.coordinates.x - a.coordinates.x); // Most recent first
  }

  /**
   * Get unvisited rooms (new territory).
   */
  getUnexplored(): PalaceRoom[] {
    return [...this.rooms.values()].filter(r => !r.visited);
  }

  /**
   * Get rooms by emotional temperature.
   */
  getByMood(mood: PalaceRoom['texture']['mood']): PalaceRoom[] {
    return [...this.rooms.values()].filter(r => r.texture.mood === mood);
  }
}
